1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteInput = {
4	  customer: Customer;
5	  items: Item[];
6	  previousContracts: number;
7	};
8	
9	const PROCESSING_FEE = 5;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const LOYALTY_DISCOUNT_RATE = -0.2;
12	const LOYALTY_THRESHOLD_YEARS = 2;
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const HIGH_ENCHANTMENT_THRESHOLD = 5;
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_BASE = 60;
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	
21	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const basePremiumForItem = (item: Item): number =>
31	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
32	
33	const isLongStandingCustomer = (customer: Customer): boolean =>
34	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
35	
36	const isHighlyEnchanted = (item: Item): boolean =>
37	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
38	
39	const isCursed = (item: Item): boolean => item.cursed === true;
40	
41	const surcharge = (base: number, applies: boolean, rate: number): number =>
42	  applies ? base * rate : 0;
43	
44	const applyPolicyModifiers = (base: number, customer: Customer): number =>
45	  base +
46	  surcharge(base, true, FIRST_INSURANCE_SURCHARGE_RATE) +
47	  surcharge(base, isLongStandingCustomer(customer), LOYALTY_DISCOUNT_RATE);
48	
49	const itemSpecificSurcharges = (item: Item, base: number): number =>
50	  surcharge(base, isCursed(item), CURSED_SURCHARGE_RATE) +
51	  surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
52	
53	const premiumForItem = (item: Item, customer: Customer): number => {
54	  const base = basePremiumForItem(item);
55	  return applyPolicyModifiers(base, customer) + itemSpecificSurcharges(item, base);
56	};
57	
58	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
59	
60	const componentGroupBase = (items: Item[]): number => {
61	  const itemBase = basePremiumForItem(items[0]);
62	  if (items.length === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
63	  return items.length * itemBase;
64	};
65	
66	const groupByType = (items: Item[]): Map<string, Item[]> => {
67	  const groups = new Map<string, Item[]>();
68	  for (const item of items) {
69	    const list = groups.get(item.type) ?? [];
70	    list.push(item);
71	    groups.set(item.type, list);
72	  }
73	  return groups;
74	};
75	
76	const componentGroupTotal = (
77	  groupItems: Item[],
78	  customer: Customer,
79	): number => applyPolicyModifiers(componentGroupBase(groupItems), customer);
80	
81	const componentsTotal = (items: Item[], customer: Customer): number => {
82	  const groups = groupByType(items);
83	  return [...groups.values()].reduce(
84	    (sum, groupItems) => sum + componentGroupTotal(groupItems, customer),
85	    0,
86	  );
87	};
88	
89	const nonComponentsTotal = (items: Item[], customer: Customer): number =>
90	  items.reduce((sum, item) => sum + premiumForItem(item, customer), 0);
91	
92	export const quote = (input: QuoteInput): { premium: number } => {
93	  const components = input.items.filter(isComponent);
94	  const nonComponents = input.items.filter((item) => !isComponent(item));
95	  const itemsTotal =
96	    nonComponentsTotal(nonComponents, input.customer) +
97	    componentsTotal(components, input.customer);
98	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
99	};
100	
101	export const claim = (_input: unknown): unknown => {
102	  return undefined;
103	};
